import{_ as a,o as t,c as s,ag as i}from"./chunks/framework.C4CIcs3_.js";const n="/elena/lifecycle.png",l="/elena/lifecycle-dark.png",g=JSON.parse('{"title":"Lifecycle","description":"","frontmatter":{},"headers":[],"relativePath":"components/lifecycle.md","filePath":"components/lifecycle.md","lastUpdated":1773698954000}'),d={name:"components/lifecycle.md"};function h(r,e,p,c,o,k){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h1><p>Elena’s component lifecycle has two parts: the standard custom element lifecycle, and a reactive update cycle triggered by property changes.</p><p>Re-renders are batched. If multiple props change at once, Elena waits until the current task finishes, then renders all changes in one update. This happens via a microtask, so the DOM is updated before the browser paints:</p><br><div class="lifecycle"><img src="'+n+'" class="light-only" alt="Elena" width="672" height="659"><img src="'+l+'" class="dark-only" alt="Elena" width="672" height="659"></div><h2 id="connectedcallback" tabindex="-1"><code>connectedCallback()</code> <a class="header-anchor" href="#connectedcallback" aria-label="Permalink to &quot;`connectedCallback()`&quot;">​</a></h2><p>Runs when the element is added to the page. Sets up props, captures text content, renders, and wires up events.</p><h2 id="willupdate" tabindex="-1"><code>willUpdate()</code> <a class="header-anchor" href="#willupdate" aria-label="Permalink to &quot;`willUpdate()`&quot;">​</a></h2><p>Runs before every render, including the first. Override to compute derived state before the template evaluates.</p><h2 id="render" tabindex="-1"><code>render()</code> <a class="header-anchor" href="#render" aria-label="Permalink to &quot;`render()`&quot;">​</a></h2><p>Returns the HTML for this component as an <code>html</code> template. Called on connect and whenever the component needs re-rendering.</p><h2 id="firstupdated" tabindex="-1"><code>firstUpdated()</code> <a class="header-anchor" href="#firstupdated" aria-label="Permalink to &quot;`firstUpdated()`&quot;">​</a></h2><p>Runs once after the first render. <code>this.element</code> is available here. Override to run one-time setup that requires the DOM.</p><h2 id="updated" tabindex="-1"><code>updated()</code> <a class="header-anchor" href="#updated" aria-label="Permalink to &quot;`updated()`&quot;">​</a></h2><p>Runs after every render, including the first. <code>this.element</code> is available here. Override to react to changes after the DOM is updated. On first connect, <code>firstUpdated()</code> runs before <code>updated()</code>.</p><h2 id="requestupdate" tabindex="-1"><code>requestUpdate()</code> <a class="header-anchor" href="#requestupdate" aria-label="Permalink to &quot;`requestUpdate()`&quot;">​</a></h2><p>Manually schedules a re-render. Use this when Elena can’t detect a change automatically. For example, when mutating an object or array in place:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.items.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">push</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;new item&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">requestUpdate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><h2 id="updatecomplete" tabindex="-1"><code>updateComplete</code> <a class="header-anchor" href="#updatecomplete" aria-label="Permalink to &quot;`updateComplete`&quot;">​</a></h2><p>A <code>Promise</code> that resolves after the next pending render finishes. Use it to wait for the DOM to settle before reading it:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.label </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Updated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">await</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.updateComplete;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.element.textContent); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;Updated&quot;</span></span></code></pre></div><p>Resolves immediately if no render is pending.</p><h2 id="disconnectedcallback" tabindex="-1"><code>disconnectedCallback()</code> <a class="header-anchor" href="#disconnectedcallback" aria-label="Permalink to &quot;`disconnectedCallback()`&quot;">​</a></h2><p>Runs when the element is removed from the page. Cleans up event listeners.</p><h2 id="adoptedcallback" tabindex="-1"><code>adoptedCallback()</code> <a class="header-anchor" href="#adoptedcallback" aria-label="Permalink to &quot;`adoptedCallback()`&quot;">​</a></h2><p>Runs when the element is moved to a new document via <code>document.adoptNode()</code>. Override to react to document changes:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adoptedCallback</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  super</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adoptedCallback</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // react to the document change</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="attributechangedcallback" tabindex="-1"><code>attributeChangedCallback()</code> <a class="header-anchor" href="#attributechangedcallback" aria-label="Permalink to &quot;`attributeChangedCallback()`&quot;">​</a></h2><p>Runs when an observed attribute changes. Updates the matching JavaScript property and triggers a re-render. Override to react to attribute changes directly:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">attributeChangedCallback</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(prop, oldValue, newValue) {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  super</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">attributeChangedCallback</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(prop, oldValue, newValue);</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // react to the change</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>prop</code></td><td><code>string</code></td><td>The attribute name that changed.</td></tr><tr><td><code>oldValue</code></td><td><code>string | null</code></td><td>The previous attribute value, or <code>null</code> if it wasn’t set.</td></tr><tr><td><code>newValue</code></td><td><code>string | null</code></td><td>The new attribute value, or <code>null</code> if the attribute was removed.</td></tr></tbody></table>',31)])])}const b=a(d,[["render",h]]);export{g as __pageData,b as default};
